from langchain_core.output_parsers import JsonOutputParser
from langchain_core.prompts import ChatPromptTemplate

parser = JsonOutputParser()
prompt = ChatPromptTemplate.from_template(
    'Output a JSON object: {{"item": "{topic}", "description": "...", "uses": [...]}}'
)
chain = prompt | llm | parser

# Each chunk is a partial dict as JSON tokens stream in
for partial in chain.stream({"topic": "neural network"}):
    print(partial)  # Grows incrementally: {}, {"item": "..."}, {"item":...,"description":...}

from langchain_core.output_parsers import BaseOutputParser
from langchain_core.exceptions import OutputParserException
from typing import Any


class BulletListParser(BaseOutputParser[list[str]]):
    """Parses output formatted as a bullet list into a Python list."""

    def parse(self, text: str) -> list[str]:
        lines = text.strip().split("\n")
        items = []
        for line in lines:
            stripped = line.strip().lstrip("•-*").strip()
            if stripped:
                items.append(stripped)
        if not items:
            raise OutputParserException(
                f"Could not parse bullet list from output: {text!r}"
            )
        return items

    def get_format_instructions(self) -> str:
        return (
            "Format your response as a bullet list, one item per line, "
            "each starting with a dash (-). Example:\n- Item one\n- Item two"
        )


bullet_parser = BulletListParser()
prompt = ChatPromptTemplate.from_messages([
    ("human", "{format_instructions}\n\nList 5 benefits of Python."),
]).partial(format_instructions=bullet_parser.get_format_instructions())

chain = prompt | llm | bullet_parser
result = chain.invoke({})
print(result)  # list[str]
